SELECT

FROM recovery_payment_collection_detail t0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.reve_id = #{request.reveId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.payment_collection_id = #{request.paymentCollectionId}


    AND t0.collection_detail_type = #{request.collectionDetailType}


    AND t0.reve_measure = #{request.reveMeasure}


    AND t0.collection_detail_amount = #{request.collectionDetailAmount}


    AND t0.remarks = #{request.remarks}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
